   322→    const std::chrono::milliseconds& timeout) {
   323→  // poll on listen socket, it allows to make timeout
   324→  std::unique_ptr<struct ::pollfd[]> events(new struct ::pollfd[1]);
   325→  events[0] = {.fd = listenSocket, .events = POLLIN};
   326→
   327→  while (true) {
   328→    int res = ::poll(events.get(), 1, timeout.count());
   329→    if (res == 0) {
   330→      throw std::runtime_error(
   331→          "waiting for processes to "
   332→          "connect has timed out");
   333→    } else if (res == -1) {
   334→      if (errno == EINTR) {
   335→        continue;
   336→      }
   337→      throw std::system_error(errno, std::system_category());
   338→    } else {
   339→      if (!(events[0].revents & POLLIN))
   340→        throw std::system_error(ECONNABORTED, std::system_category());
   341→      break;
   342→    }
   343→  }
