   338→// `errno` is only meaningful when it fails. E.g., a  successful `fork()` sets
   339→// `errno` to `EINVAL` in child process on some macos
   340→// (https://stackoverflow.com/a/20295079), and thus `errno` should really only
   341→// be inspected if an error occured.
   342→//
   343→// `success_cond` is an expression used to check if an error has happend. So for
   344→// `fork()`, we can use `SYSCHECK(pid = fork(), pid != -1)`. The function output
   345→// is stored in variable `__output` and may be used in `success_cond`.
   346→#define SYSCHECK(expr, success_cond)                            \
   347→  while (true) {                                                \
   348→    auto __output = (expr);                                     \
   349→    (void)__output;                                             \
   350→    if (!(success_cond)) {                                      \
   351→      if (errno == EINTR) {                                     \
   352→        continue;                                               \
   353→      } else if (errno == EAGAIN || errno == EWOULDBLOCK) {     \
   354→        throw std::runtime_error("Socket Timeout");             \
   355→      } else {                                                  \
   356→        throw std::system_error(errno, std::system_category()); \
   357→      }                                                         \
   358→    } else {                                                    \
   359→      break;                                                    \
   360→    }                                                           \
   361→  }
   362→
   363→// Most functions indicate error by returning `-1`. This is a helper macro for
   364→// this common case with `SYSCHECK`.
   365→#define SYSCHECK_ERR_RETURN_NEG1(expr) SYSCHECK(expr, __output != -1)
