   392→// Send and receive
   393→template <typename T>
   394→void sendBytes(
   395→    int socket,
   396→    const T* buffer,
   397→    size_t length,
   398→    bool moreData = false) {
   399→  size_t bytesToSend = sizeof(T) * length;
   400→  if (bytesToSend == 0) {
   401→    return;
   402→  }
   403→
   404→  auto bytes = reinterpret_cast<const uint8_t*>(buffer);
   405→  uint8_t* currentBytes = const_cast<uint8_t*>(bytes);
   406→
   407→  int flags = 0;
   408→
   409→#ifdef MSG_MORE
   410→  if (moreData) { // there is more data to send
   411→    flags |= MSG_MORE;
   412→  }
   413→#endif
   414→
   415→  while (bytesToSend > 0) {
   416→    ssize_t bytesSent;
   417→    SYSCHECK_ERR_RETURN_NEG1(
   418→        bytesSent = ::send(socket, currentBytes, bytesToSend, flags))
   419→    if (bytesSent == 0) {
   420→      throw std::system_error(ECONNRESET, std::system_category());
   421→    }
   422→
   423→    bytesToSend -= bytesSent;
   424→    currentBytes += bytesSent;
   425→  }
   426→}
   427→
   428→template <typename T>
   429→void recvBytes(int socket, T* buffer, size_t length) {
   430→  size_t bytesToReceive = sizeof(T) * length;
   431→  if (bytesToReceive == 0) {
   432→    return;
   433→  }
   434→
   435→  auto bytes = reinterpret_cast<uint8_t*>(buffer);
   436→  uint8_t* currentBytes = bytes;
   437→
   438→  while (bytesToReceive > 0) {
   439→    ssize_t bytesReceived;
   440→    SYSCHECK_ERR_RETURN_NEG1(
   441→        bytesReceived = ::recv(socket, currentBytes, bytesToReceive, 0))
   442→    if (bytesReceived == 0) {
   443→      throw std::system_error(ECONNRESET, std::system_category());
   444→    }
   445→
   446→    bytesToReceive -= bytesReceived;
   447→    currentBytes += bytesReceived;
   448→  }
   449→}
