   452→template <typename T>
   453→void sendVector(int socket, const std::vector<T>& vec, bool moreData = false) {
   454→  SizeType size = vec.size();
   455→  sendBytes<SizeType>(socket, &size, 1, true);
   456→  sendBytes<T>(socket, vec.data(), size, moreData);
   457→}
   458→
   459→// receive a vector as sent in sendVector
   460→template <typename T>
   461→std::vector<T> recvVector(int socket) {
   462→  SizeType valueSize;
   463→  recvBytes<SizeType>(socket, &valueSize, 1);
   464→  std::vector<T> value(valueSize);
   465→  recvBytes<T>(socket, value.data(), value.size());
   466→  return value;
